// ---------------------------------------------------------------------------
// Stagger resolver — not in tokens.js because it requires runtime context
// ---------------------------------------------------------------------------

/**
 * Returns an array of delay values (ms) for `count` elements.
 *
 * from:'start'  — delays = [0, interval, 2*interval, …], capped at cap.
 * from:'center' — center element gets 0; delay increases with distance.
 *                 For even counts, the two center slots share the minimum delay.
 *
 * @param {{ interval: number, from: string, cap: number|null }} config
 * @param {number} count — total number of elements
 * @returns {number[]} — delay in ms for each element index [0..count-1]
 */
function resolveStagger(config, count) {
  const { interval, from, cap } = config;

  if (from === 'start') {
    return Array.from({ length: count }, (_, i) => {
      const delay = i * interval;
      return cap !== null ? Math.min(delay, cap) : delay;
    });
  }

  if (from === 'center') {
    const center = (count - 1) / 2;
    return Array.from({ length: count }, (_, i) => {
      const distance = Math.abs(i - center);
      const delay = Math.round(distance * interval);
      return cap !== null ? Math.min(delay, cap) : delay;
    });
  }

  // Fallback — all at zero
  return Array.from({ length: count }, () => 0);
}

