// ---------------------------------------------------------------------------
// Story 1 — ListStagger
// ---------------------------------------------------------------------------
export const ListStagger = {
  name: 'List stagger',
  render: () => {
    const config = STAGGER_CONFIGS.list;
    const COUNT = 8;
    const delays = resolveStagger(config, COUNT);
    const enterDuration = parseInt(TRANSITIONS.enter.duration, 10);
    const enterEasing = cubicBezierCSS(TRANSITIONS.enter.easing);

    const items = Array.from({ length: COUNT }, (_, i) => `
      <div class="stagger-item" id="list-item-${i}" style="
        display: flex; align-items: center; gap: 12px;
        padding: 10px 16px; background: #e8e8e8; border-radius: 20px;
        font-size: 13px; color: #1a1a1a; font-weight: 500;
        opacity: 0; transform: translateY(12px);
        margin-bottom: 8px; width: fit-content; min-width: 160px;
      ">
        <span style="
          width: 24px; height: 24px; border-radius: 50%;
          background: #888; display: flex; align-items: center;
          justify-content: center; color: #fff; font-size: 11px; font-weight: 700;
          flex-shrink: 0;
        ">${i + 1}</span>
        <span>Item ${i + 1}</span>
        <span style="
          margin-left: auto; font-family: 'SF Mono', 'Fira Code', monospace;
          font-size: 10px; color: #aaa;
        ">+${delays[i]}ms</span>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .list-container { display: flex; flex-direction: column; align-items: flex-start; }
      </style>
      <div class="page">
        <div class="page-title">Motion / Stagger</div>
        <div class="page-subtitle">List stagger</div>
        <div class="page-description">
          <code style="font-family: 'SF Mono', 'Fira Code', monospace; background: #eee; padding: 1px 5px; border-radius: 3px;">motion.stagger.list</code>
          — sequential entrance from start, 20ms interval, 500ms cap.
          Each item uses <code style="font-family: 'SF Mono', 'Fira Code', monospace; background: #eee; padding: 1px 5px; border-radius: 3px;">motion.transition.enter</code>
          as the base animation; the stagger controls only the per-element delay.
        </div>
        <button class="play-btn" id="listBtn">Play</button>
        <div class="list-container" id="listContainer">
          ${items}
        </div>
        <table class="token-table" style="margin-top: 32px;">
          <thead>
            <tr>
              <th>Token</th>
              <th>Interval</th>
              <th>Direction</th>
              <th>Cap</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>motion.stagger.list</td>
              <td>${config.interval}ms</td>
              <td>${config.from}</td>
              <td>${config.cap}ms</td>
            </tr>
          </tbody>
        </table>
      </div>
    `;

    const btn = el.querySelector('#listBtn');
    let running = false;

    btn.addEventListener('click', () => {
      if (running) return;
      running = true;
      btn.disabled = true;

      // Reset all items
      for (let i = 0; i < COUNT; i++) {
        const item = el.querySelector(`#list-item-${i}`);
        item.style.opacity = '0';
        item.style.transform = 'translateY(12px)';
      }

      // Animate each with its stagger delay
      let lastFinish = null;
      for (let i = 0; i < COUNT; i++) {
        const item = el.querySelector(`#list-item-${i}`);
        const anim = item.animate(
          [
            { opacity: 0, transform: 'translateY(12px)' },
            { opacity: 1, transform: 'translateY(0)' },
          ],
          {
            duration: enterDuration,
            easing: enterEasing,
            delay: delays[i],
            fill: 'forwards',
          }
        );
        if (i === COUNT - 1) lastFinish = anim;
      }

      if (lastFinish) {
        lastFinish.onfinish = () => {
          running = false;
          btn.disabled = false;
        };
      }
    });

    return el;
  },
};

