// Story 2 — GridStagger
// ---------------------------------------------------------------------------
export const GridStagger = {
  name: 'Grid stagger',
  render: () => {
    const config = STAGGER_CONFIGS.grid;
    const COLS = 3;
    const ROWS = 3;
    const COUNT = COLS * ROWS;
    const delays = resolveStagger(config, COUNT);
    const enterDuration = parseInt(TRANSITIONS.enter.duration, 10);
    const enterEasing = cubicBezierCSS(TRANSITIONS.enter.easing);

    const cells = Array.from({ length: COUNT }, (_, i) => `
      <div class="grid-cell" id="grid-cell-${i}" style="
        width: 100px; height: 100px;
        background: #e8e8e8; border-radius: 8px;
        display: flex; align-items: center; justify-content: center;
        position: relative;
        opacity: 0; transform: translateY(12px);
      ">
        <span style="font-size: 12px; color: #888; font-weight: 500;">Cell ${i + 1}</span>
        <span class="delay-overlay" id="delay-${i}" style="
          display: none; position: absolute; bottom: 6px; right: 8px;
          font-family: 'SF Mono', 'Fira Code', monospace; font-size: 10px;
          color: #555;
        ">+${delays[i]}ms</span>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        .grid-container {
          display: grid;
          grid-template-columns: repeat(${COLS}, 100px);
          gap: 10px;
          width: fit-content;
        }
      </style>
      <div class="page">
        <div class="page-title">Motion / Stagger</div>
        <div class="page-subtitle">Grid stagger</div>
        <div class="page-description">
          <code style="font-family: 'SF Mono', 'Fira Code', monospace; background: #eee; padding: 1px 5px; border-radius: 3px;">motion.stagger.grid</code>
          — elements animate from the center outward (30ms interval, no cap).
          The delay for each grid position is shown as an overlay after the animation completes.
        </div>
        <button class="play-btn" id="gridBtn">Play</button>
        <div class="grid-container" id="gridContainer">
          ${cells}
        </div>
        <table class="token-table" style="margin-top: 32px;">
          <thead>
            <tr>
              <th>Token</th>
              <th>Interval</th>
              <th>Direction</th>
              <th>Cap</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>motion.stagger.grid</td>
              <td>${config.interval}ms</td>
              <td>${config.from}</td>
              <td>none</td>
            </tr>
          </tbody>
        </table>
      </div>
    `;

    const btn = el.querySelector('#gridBtn');
    let running = false;

    btn.addEventListener('click', () => {
      if (running) return;
      running = true;
      btn.disabled = true;

      // Hide overlays and reset cells
      for (let i = 0; i < COUNT; i++) {
        const cell = el.querySelector(`#grid-cell-${i}`);
        const overlay = el.querySelector(`#delay-${i}`);
        cell.style.opacity = '0';
        cell.style.transform = 'translateY(12px)';
        overlay.style.display = 'none';
      }

      let lastFinish = null;
      for (let i = 0; i < COUNT; i++) {
        const cell = el.querySelector(`#grid-cell-${i}`);
        const overlay = el.querySelector(`#delay-${i}`);
        const anim = cell.animate(
          [
            { opacity: 0, transform: 'translateY(12px)' },
            { opacity: 1, transform: 'translateY(0)' },
          ],
          {
            duration: enterDuration,
            easing: enterEasing,
            delay: delays[i],
            fill: 'forwards',
          }
        );

        anim.onfinish = () => {
          overlay.style.display = 'block';
        };

        if (i === COUNT - 1) lastFinish = anim;
      }

      if (lastFinish) {
        lastFinish.onfinish = () => {
          el.querySelector(`#delay-${COUNT - 1}`).style.display = 'block';
          running = false;
          btn.disabled = false;
        };
      }
    });

    return el;
  },
};

